  msProjectName:'',msCustomerInfo:{name:'',phone:'',address:'',designer:'',designerPhone:'',plan:'luxury',quoteMode:'full',date:new Date().toISOString().split('T')[0],area:''},msRooms:[],importSelectedFileId:null,msEditingRoomId:null,
  products:[],pdbSelectedMainCat:null,pdbSelectedSubCat:null,editingProductId:null,addProdSelectedIds:[],
  customNotes:'',bossPassword:'888888',costRates:{luxury:0.65,premium:0.60},
