addRow(['客户：'+(ci.name||''),'联系方式：'+(ci.phone||''),'设计师：'+(ci.designer||''),'设计师电话：'+(ci.designerPhone||'')]);mergeRow(R-1,0,1);mergeRow(R-1,2,3);mergeRow(R-1,4,9);
addRow(['地址：'+(ci.address||''),'','日期：'+(ci.date||''),'','面积：'+(ci.area||'')+'㎡']);mergeRow(R-1,0,3);mergeRow(R-1,4,9);
emptyRow();
addRow(['序号','项目名称','品牌','型号','规格','数量','单位','单价','金额','说明']);
