Object.keys(subG).forEach(function(subId){var subI=subG[subId];var sT=subI.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
var r1=Array(COLS).fill('');r1[0]='▸ '+getSubCatLabel(categoryId,subId);r1[8]='¥'+fmt(sT);addRow(r1);mergeRow(R-1,0,7);mergeRow(R-1,8,9);
subI.forEach(function(q){var amt=q.quantity*q.unitPrice;totalAmount+=amt;addRow([seq,q.name,q.brand||'',q.model||'',q.specifications||'',q.quantity,q.unit,q.unitPrice,amt,q.description||'']);seq++})});
