function renderMsRoomList(){var el=document.getElementById('msRoomList');if(!S.msRooms.length){el.innerHTML='<div class="empty-state"><div class="icon">📐</div><p>点击上方按钮添加房间</p></div>';return}var fg={};S.msRooms.forEach(function(r){var f=r.floor||'一楼';if(!fg[f])fg[f]=[];fg[f].push(r)});var floors=Object.keys(fg).sort(function(a,b){return floorSortKey(a)-floorSortKey(b)});var html='';floors.forEach(function(fl){html+='<div class="floor-header">🏗️ '+esc(fl)+'</div>';fg[fl].forEach(function(r){var st=S.spaceTypes.find(function(s){return s.id===r.spaceTypeId});var wa=Math.max(0,r.perimeter*r.height-(r.doors||[]).reduce(function(s,d){return s+d.width*d.height},0)-(r.windows||[]).reduce(function(s,w){return s+w.width*w.height},0));var sk=Math.max(0,r.perimeter-(r.doors||[]).reduce(function(s,d){return s+d.width},0));html+='<div class="ms-room-item"><div class="ms-room-header"><span class="ms-room-name">'+(st?st.icon:'')+' '+esc(r.name)+'</span><span class="ms-room-type">'+(st?st.name:'')+'</span></div><div class="ms-room-dims">面积: '+r.area+'㎡ | 周长: '+r.perimeter+'m | 高: '+r.height+'m</div><div class="ms-room-detail"><div class="ms-detail-tag">地面 <span>'+r.area+'</span> ㎡</div><div class="ms-detail-tag">墙面 <span>'+fmt(wa)+'</span> ㎡</div><div class="ms-detail-tag">踢脚线 <span>'+fmt(sk)+'</span> m</div></div><div class="ms-room-actions"><button class="btn btn-outline btn-sm" onclick="editMsRoom(\''+r.id+'\')">编辑</button><button class="btn btn-danger btn-sm" onclick="deleteMsRoom(\''+r.id+'\')">删除</button></div></div>'})});el.innerHTML=html}
function openMsRoomEditor(rid){S.msEditingRoomId=rid||null;var r=rid?S.msRooms.find(function(x){return x.id===rid}):null;document.getElementById('msRoomEditorTitle').textContent=r?'编辑房间':'添加房间';var stO=S.spaceTypes.map(function(s){return'<option value="'+s.id+'" '+(r&&r.spaceTypeId===s.id?'selected':'')+'>'+s.icon+' '+s.name+'</option>'}).join('');var flO=FLOOR_ORDER.map(function(f){return'<option value="'+f+'" '+(r&&r.floor===f?'selected':'')+'>'+f+'</option>'}).join('');var cO=['衣柜','书柜','护墙板','门','橱柜上柜','橱柜下柜','电视柜','踢脚线','特殊五金','特殊工艺'].map(function(n){return'<option value="'+n+'">'+n+'</option>'}).join('');document.getElementById('msRoomEditorBody').innerHTML='<div class="form-grid"><div class="form-group"><label>房间名称</label><input id="mreName" value="'+(r?esc(r.name):'')+'"></div><div class="form-group"><label>空间类型</label><select id="mreSpaceType">'+stO+'</select></div><div class="form-group"><label>楼层</label><select id="mreFloor">'+flO+'</select></div><div class="form-group"><label>面积 (㎡)</label><input type="number" id="mreArea" value="'+(r?r.area:'')+'" step="0.01"></div><div class="form-group"><label>周长 (m)</label><input type="number" id="mrePerimeter" value="'+(r?r.perimeter:'')+'" step="0.01"></div><div class="form-group"><label>高度 (m)</label><input type="number" id="mreHeight" value="'+(r?r.height:'')+'" step="0.01"></div></div><div class="sub-section"><h4>门</h4><div id="mreDoors">'+(r?(r.doors||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsDoor()">+ 添加</button></div><div class="sub-section"><h4>窗户</h4><div id="mreWindows">'+(r?(r.windows||[]).map(dwRow).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsWindow()">+ 添加</button></div><div class="sub-section"><h4>定制</h4><div style="margin-bottom:6px"><select id="msCPS"><option value="">选择预设...</option>'+cO+'</select> <button class="btn btn-outline btn-sm" onclick="addMsPresetCustom()">添加</button></div><div id="mreCustomItems">'+(r?(r.customItems||[]).map(msCR).join(''):'')+'</div><button class="btn btn-outline btn-sm" onclick="addMsCustomItem()">+ 自定义</button></div>';openModal('msRoomEditorModal')}
function editMsRoom(id){openMsRoomEditor(id)}function addMsDoor(){var c=document.getElementById('mreDoors');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}function addMsWindow(){var c=document.getElementById('mreWindows');var d=document.createElement('div');d.innerHTML=dwRow({});c.appendChild(d.firstElementChild)}function msCR(d){d=d||{};var t=d.type||'';var isLH=(t==='衣柜'||t==='书柜'||t==='护墙板'||t==='门'||t==='');var isL=(t==='橱柜上柜'||t==='橱柜下柜'||t==='电视柜'||t==='踢脚线');var isNPQ=(t==='特殊五金'||t==='特殊工艺');var h='<div class="custom-row"><input type="hidden" class="cr-type" value="'+esc(t)+'"><input placeholder="名称" value="'+esc(d.name||'')+'" style="width:90px" class="cr-name">';if(isNPQ){h+='<input placeholder="数量" value="'+(d.quantity||1)+'" type="number" style="width:55px" class="cr-qty"><input placeholder="单位" value="'+esc(d.unit||'项')+'" style="width:45px" class="cr-unit2">'}else{h+='<input placeholder="长" value="'+(d.length||'')+'" type="number" step="0.01" style="width:60px" class="cr-length">';if(isLH)h+='<input placeholder="高" value="'+(d.height||'')+'" type="number" step="0.01" style="width:60px" class="cr-height">'}h+='<button class="btn-x" onclick="this.parentElement.remove()">×</button></div>';return h}
function addMsCustomItem(){var c=document.getElementById('mreCustomItems');var d=document.createElement('div');d.innerHTML=msCR({});c.appendChild(d.firstElementChild)}function addMsPresetCustom(){var s=document.getElementById('msCPS');if(!s.value)return;var c=document.getElementById('mreCustomItems');var d=document.createElement('div');d.innerHTML=msCR({name:s.value,type:s.value});c.appendChild(d.firstElementChild);s.value=''}
function saveMsRoom(){var name=document.getElementById('mreName').value.trim();var stId=document.getElementById('mreSpaceType').value;var floor=document.getElementById('mreFloor').value||'一楼';var area=parseFloat(document.getElementById('mreArea').value)||0;var peri=parseFloat(document.getElementById('mrePerimeter').value)||0;var h=parseFloat(document.getElementById('mreHeight').value)||0;if(!area||!peri||!h){showToast('请输入面积、周长和高度');return}var doors=[],windows=[],customs=[];document.querySelectorAll('#mreDoors .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)doors.push({width:w,height:h})});document.querySelectorAll('#mreWindows .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)windows.push({width:w,height:h})});document.querySelectorAll('#mreCustomItems .custom-row').forEach(function(row){var type=(row.querySelector('.cr-type')||{}).value||'';var n=(row.querySelector('.cr-name')||{}).value.trim();if(!n)return;var obj={name:n,type:type};var qtyEl=row.querySelector('.cr-qty');if(qtyEl){obj.quantity=parseFloat(qtyEl.value)||1;obj.unit=(row.querySelector('.cr-unit2')||{}).value||'项';customs.push(obj)}else{obj.length=parseFloat((row.querySelector('.cr-length')||{}).value)||0;var hEl=row.querySelector('.cr-height');if(hEl)obj.height=parseFloat(hEl.value)||0;if(obj.length||obj.height)customs.push(obj)}});var st=S.spaceTypes.find(function(s){return s.id===stId});var rd={id:S.msEditingRoomId||uid(),name:name||(st?st.name:'房间'),spaceTypeId:stId,floor:floor,area:area,perimeter:peri,height:h,doors:doors,windows:windows,customItems:customs};if(S.msEditingRoomId){var idx=S.msRooms.findIndex(function(x){return x.id===S.msEditingRoomId});if(idx>=0)S.msRooms[idx]=rd}else S.msRooms.push(rd);closeModal('msRoomEditorModal');renderMsRoomList();showToast('已保存');markDirty()}
