function getFloorSpecOptions(type,selected){
  var opts=MATERIAL_SPECS[type]||[];
  if(!opts.length)return'<option value="">-</option>';
  return opts.map(function(o){return'<option value="'+o.value+'" '+(selected===o.value?'selected':'')+'>'+o.label+' (¥'+o.price+'/㎡)</option>'}).join('');
}

function getWallSpecOptions(type,selected){
  var opts=MATERIAL_SPECS[type]||[];
  if(!opts.length)return'<option value="">-</option>';
  return opts.map(function(o){return'<option value="'+o.value+'" '+(selected===o.value?'selected':'')+'>'+o.label+' (¥'+o.price+'/㎡)</option>'}).join('');
}

function getCeilingSpecOptions(type,selected){
  if(type==='none')return'<option value="none" selected>不吊顶</option>';
  if(type==='gypsum')return'<option value="flat" '+(selected==='flat'?'selected':'')+'>平顶</option><option value="shape" '+(selected==='shape'?'selected':'')+'>造型顶</option><option value="light_groove" '+(selected==='light_groove'?'selected':'')+'>灯槽顶</option>';
  if(type==='no_main_light')return'<option value="flat" '+(selected==='flat'?'selected':'')+'>平顶+射灯</option><option value="step" '+(selected==='step'?'selected':'')+'>跌级吊顶</option><option value="arc" '+(selected==='arc'?'selected':'')+'>弧形吊顶</option>';
  if(type==='pvc')return'<option value="white" '+(selected==='white'?'selected':'')+'>白色铝扣板</option><option value="grey" '+(selected==='grey'?'selected':'')+'>灰色铝扣板</option>';
  return'<option value="">-</option>';
}

function updateFloorSpecs(){
  var type=document.getElementById('reFloorType').value;
  document.getElementById('reFloorSpec').innerHTML=getFloorSpecOptions(type,'');
}

function updateWallSpecs(){
  var type=document.getElementById('reWallType').value;
  document.getElementById('reWallSpec').innerHTML=getWallSpecOptions(type,'');
}

function updateCeilingSpecs(){
  var type=document.getElementById('reCeilingType').value;
  document.getElementById('reCeilingSpec').innerHTML=getCeilingSpecOptions(type,'');
}
