function saveRoom(){pushUndoState();var name=document.getElementById('reName').value.trim();var stId=document.getElementById('reSpaceType').value;var floor=document.getElementById('reFloor').value||'一楼';var area=parseFloat(document.getElementById('reArea').value)||0;var peri=parseFloat(document.getElementById('rePerimeter').value)||0;var h=parseFloat(document.getElementById('reHeight').value)||0;if(!area||!peri||!h){showToast('请输入面积、周长和高度');return}var doors=[],windows=[],eqs=[],cus=[],fws=[];document.querySelectorAll('#reDoors .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)doors.push({width:w,height:h})});document.querySelectorAll('#reWindows .door-win-row').forEach(function(row){var i=row.querySelectorAll('input');var w=parseFloat(i[0].value)||0,h=parseFloat(i[1].value)||0;if(w&&h)windows.push({width:w,height:h})});document.querySelectorAll('#reEquipItems .equip-row').forEach(function(row){var i=row.querySelectorAll('input');if(i[0].value.trim()&&parseFloat(i[2].value))eqs.push({name:i[0].value.trim(),brand:i[1].value.trim(),unitPrice:parseFloat(i[2].value)||0,quantity:parseFloat(i[3].value)||1,unit:i[4].value.trim()||'项'})});document.querySelectorAll('#reCustomItems .custom-row').forEach(function(row){var type=(row.querySelector('.cr-type')||{}).value||'';var n=(row.querySelector('.cr-name')||{}).value.trim();var price=parseFloat((row.querySelector('.cr-price')||{}).value)||0;if(!n)return;var obj={name:n,type:type,unitPrice:price};var qtyEl=row.querySelector('.cr-qty');if(qtyEl){obj.quantity=parseFloat(qtyEl.value)||1;obj.unit=(row.querySelector('.cr-unit2')||{}).value||'项';cus.push(obj)}else{obj.length=parseFloat((row.querySelector('.cr-length')||{}).value)||0;var hEl=row.querySelector('.cr-height');if(hEl)obj.height=parseFloat(hEl.value)||0;if(obj.length||obj.height)cus.push(obj)}});document.querySelectorAll('#reFwItems .fw-row').forEach(function(row){var i=row.querySelectorAll('input');if(i[0].value.trim()&&parseFloat(i[1].value)&&parseFloat(i[2].value))fws.push({name:i[0].value.trim(),area:parseFloat(i[1].value)||0,unitPrice:parseFloat(i[2].value)||0})});var floorMat={type:document.getElementById('reFloorType').value,spec:document.getElementById('reFloorSpec').value,craft:document.getElementById('reFloorCraft').value};var wallMat={type:document.getElementById('reWallType').value,spec:document.getElementById('reWallSpec').value};var ceilingMat={type:document.getElementById('reCeilingType').value,spec:document.getElementById('reCeilingSpec').value};var rd={id:S.editingRoomId||uid(),name:name||'房间',spaceTypeId:stId,floor:floor,area:area,perimeter:peri,height:h,doors:doors,windows:windows,hasEquipment:!!document.getElementById('reHasEquip').checked,hasCustom:!!document.getElementById('reHasCustom').checked,hasFeatureWall:!!document.getElementById('reHasFeatureWall').checked,equipmentItems:eqs,customItems:cus,featureWallItems:fws,floorMaterial:floorMat,wallMaterial:wallMat,ceilingMaterial:ceilingMat};if(S.editingRoomId){var idx=S.rooms.findIndex(function(x){return x.id===S.editingRoomId});if(idx>=0){S.rooms[idx]=rd;S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!==rd.id});S.quoteItems=S.quoteItems.concat(generateRoomItems(rd))}}else{S.rooms.push(rd);S.quoteItems=S.quoteItems.concat(generateRoomItems(rd))}regenerateUtilityItems();closeModal('roomEditorModal');renderRoomList();renderQuoteTable();renderSummary();showToast('已保存');markDirty()}
function deleteRoom(id){pushUndoState();if(!confirm('确定删除？'))return;S.rooms=S.rooms.filter(function(r){return r.id!==id});S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!==id});renderRoomList();renderQuoteTable();renderSummary();markDirty()}
function exportRooms(){if(!S.rooms.length){showToast('没有房间可导出');return}var data={version:1,type:'room_export',exportDate:new Date().toISOString(),customerInfo:S.customerInfo,rooms:S.rooms.map(function(r){return{name:r.name,spaceTypeId:r.spaceTypeId,floor:r.floor||'一楼',area:r.area,perimeter:r.perimeter,height:r.height,doors:r.doors||[],windows:r.windows||[],hasEquipment:r.hasEquipment||false,hasCustom:r.hasCustom||false,hasFeatureWall:r.hasFeatureWall||false,equipmentItems:r.equipmentItems||[],customItems:r.customItems||[],featureWallItems:r.featureWallItems||[],floorMaterial:r.floorMaterial||{},wallMaterial:r.wallMaterial||{},ceilingMaterial:r.ceilingMaterial||{}}})};var blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});var url=URL.createObjectURL(blob);var a=document.createElement('a');a.href=url;a.download='房间信息_'+(S.customerInfo.address||S.customerInfo.name||'导出')+'_'+new Date().toISOString().split('T')[0]+'.json';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);showToast('房间信息已导出')}
function importRoomsFromFile(){var input=document.createElement('input');input.type='file';input.accept='.json';input.onchange=function(e){var file=e.target.files[0];if(!file)return;var reader=new FileReader();reader.onload=function(ev){try{var data=JSON.parse(ev.target.result);if(data.type!=='room_export'){showToast('无效的房间导出文件');return}var rooms=data.rooms||[];if(!rooms.length){showToast('文件中没有房间数据');return}var n=0;rooms.forEach(function(r){S.msRooms.push({id:uid(),name:r.name,spaceTypeId:r.spaceTypeId,floor:r.floor||'一楼',area:r.area,perimeter:r.perimeter,height:r.height,doors:r.doors||[],windows:r.windows||[],customItems:r.customItems||[]});n++});if(data.customerInfo){var ci=data.customerInfo;if(ci.name)document.getElementById('msCustName').value=ci.name;if(ci.phone)document.getElementById('msCustPhone').value=ci.phone;if(ci.address)document.getElementById('msCustAddress').value=ci.address;if(ci.designer)document.getElementById('msCustDesigner').value=ci.designer;if(ci.designerPhone)document.getElementById('msCustDesignerPhone').value=ci.designerPhone;if(ci.plan)document.getElementById('msCustPlan').value=ci.plan;if(ci.quoteMode)document.getElementById('msCustQuoteMode').value=ci.quoteMode;if(ci.date)document.getElementById('msCustDate').value=ci.date;if(ci.area)document.getElementById('msCustArea').value=ci.area;onMsCustChange()}renderMsRoomList();markDirty();showToast('已导入'+n+'个房间')}catch(err){showToast('导入失败: 文件格式错误')}};reader.readAsText(file)};input.click()}
function moveRoom(id,dir){var idx=S.rooms.findIndex(function(r){return r.id===id});if(idx<0)return;var ni=idx+dir;if(ni<0||ni>=S.rooms.length)return;var tmp=S.rooms[idx];S.rooms[idx]=S.rooms[ni];S.rooms[ni]=tmp;renderRoomList();renderQuoteTable();renderSummary();markDirty()}
function toggleRoomCollapse(id){
  var isSecondLevel=document.getElementById('icon-'+id)&&document.getElementById('icon-'+id).closest('tr')&&document.getElementById('icon-'+id).closest('tr').classList.contains('sub-row');
  var rows,icon;
  if(isSecondLevel){
    rows=document.querySelectorAll('tr[data-room-id2="'+id+'"]');
  }else{
    rows=document.querySelectorAll('tr[data-room-id="'+id+'"]');
  }
  icon=document.getElementById('icon-'+id);
  var isCollapsed=rows.length>0&&rows[0].classList.contains('collapsed');
  rows.forEach(function(row){
    if(isCollapsed)row.classList.remove('collapsed');
    else row.classList.add('collapsed');
  });
  if(icon)icon.textContent=isCollapsed?'▼':'▶';
}
function toggleSectionCollapse(sectionId){toggleRoomCollapse(sectionId)}
function toggleSidebarFloor(floor){var items=document.querySelectorAll('[data-sidebar-floor="'+floor+'"]');var icon=document.getElementById('sidebar-icon-'+floor);var isCollapsed=items.length>0&&items[0].classList.contains('sidebar-collapsed');items.forEach(function(el){if(isCollapsed)el.classList.remove('sidebar-collapsed');else el.classList.add('sidebar-collapsed')});if(icon)icon.textContent=isCollapsed?'▼':'▶'}
function toggleSidebarRoom(roomId){var details=document.getElementById('sidebar-details-'+roomId);var icon=document.getElementById('sidebar-icon-'+roomId);if(!details)return;var isCollapsed=details.classList.contains('sidebar-collapsed');if(isCollapsed)details.classList.remove('sidebar-collapsed');else details.classList.add('sidebar-collapsed');if(icon)icon.textContent=isCollapsed?'▼':'▶'}

// ==================== QUOTE GENERATION ====================
function generateRoomItems(room){var items=[],fa=room.area,ca=room.area,da=(room.doors||[]).reduce(function(s,d){return s+d.width*d.height},0),wa2=(room.windows||[]).reduce(function(s,w){return s+w.width*w.height},0),wa=Math.max(0,room.perimeter*room.height-da-wa2),sk=Math.max(0,room.perimeter-(room.doors||[]).reduce(function(s,d){return s+d.width},0)),ww=(room.windows||[]).reduce(function(s,w){return s+w.width},0),dp=(room.doors||[]).reduce(function(s,d){return s+(d.width+d.height)*2},0),wp=(room.windows||[]).reduce(function(s,w){return s+(w.width+w.height)*2},0),ws=(room.windows||[]).length;
var wallDeduct=0;
if(room.hasCustom)(room.customItems||[]).forEach(function(cp){var t=cp.type||'';if(t==='护墙板'||t==='衣柜'){wallDeduct+=(cp.length||0)*(cp.height||0)}});
if(room.hasFeatureWall)(room.featureWallItems||[]).forEach(function(fw){wallDeduct+=fw.area||0});
wa=Math.max(0,wa-wallDeduct);
var app=S.materials.filter(function(m){if(m.calcType==='building_area')return false;if(m.name==='窗帘盒制作')return false;if(!m.spaceTypeFilter||!m.spaceTypeFilter.length)return true;return m.spaceTypeFilter.includes(room.spaceTypeId)});
var floorType=(room.floorMaterial&&room.floorMaterial.type)||'';var wallType=(room.wallMaterial&&room.wallMaterial.type)||'';var ceilingType=(room.ceilingMaterial&&room.ceilingMaterial.type)||'';
var floorExcludeIds=[];var wallExcludeIds=[];var ceilingExcludeIds=[];
if(floorType==='flooring'){floorExcludeIds=['m40','m41','m44','m46']}else if(floorType==='ceramic_tile'){floorExcludeIds=['m43','m44']}else if(floorType==='marble'){floorExcludeIds=['m40','m41','m43','m46']}
if(wallType==='paint'){wallExcludeIds=['m42','m47','m71','m72','m73']}else if(wallType==='wallpaper'){wallExcludeIds=['m42','m47','m71','m72','m73']}else if(wallType==='wall_tile'){wallExcludeIds=['m71','m72','m73']}
if(ceilingType==='none'){ceilingExcludeIds=['m50','m51','m80','m81']}
app=app.filter(function(m){if(m.calcType==='floor_area'&&floorExcludeIds.indexOf(m.id)>=0)return false;if(m.calcType==='wall_area'&&wallExcludeIds.indexOf(m.id)>=0)return false;if(m.calcType==='ceiling_area'&&ceilingExcludeIds.indexOf(m.id)>=0)return false;return true});
app.forEach(function(mat){var qty=0;switch(mat.calcType){case'wall_area':qty=wa;break;case'floor_area':qty=fa;break;case'ceiling_area':qty=ca;break;case'skirting':qty=sk;break;case'door_count':qty=(room.doors||[]).length;break;case'door_perimeter':qty=dp;break;case'window_perimeter':qty=wp;break;case'window_width':qty=ww;break;case'window_sill':qty=ws;break;case'item':qty=1;break;case'length_m':qty=ww;break}if(qty>0&&mat.prices[S.currentPlan]>0){var desc=mat.description||'';if(mat.processDetail&&mat.processDetail[S.currentPlan])desc=mat.processDetail[S.currentPlan];else if(mat.brand&&mat.brand!=='-')desc+=' | '+mat.brand;items.push({id:uid(),materialId:mat.id,roomId:room.id,name:mat.name,quantity:Math.round(qty*100)/100,unit:mat.unit,unitPrice:mat.prices[S.currentPlan],description:desc,category:mat.category})}});
if(room.ceilingMaterial&&room.ceilingMaterial.type&&room.ceilingMaterial.type!=='none'){var cbMat=S.materials.find(function(m){return m.name==='窗帘盒制作'});if(cbMat&&cbMat.prices[S.currentPlan]>0&&ww>0){var cbDesc=cbMat.description||'';if(cbMat.processDetail&&cbMat.processDetail[S.currentPlan])cbDesc=cbMat.processDetail[S.currentPlan];else if(cbMat.brand&&cbMat.brand!=='-')cbDesc+=' | '+cbMat.brand;items.push({id:uid(),materialId:cbMat.id,roomId:room.id,name:cbMat.name,quantity:Math.round(ww*100)/100,unit:cbMat.unit,unitPrice:cbMat.prices[S.currentPlan],description:cbDesc,category:cbMat.category})}}
if(room.hasEquipment)room.equipmentItems.forEach(function(eq){items.push({id:uid(),roomId:room.id,name:eq.name,quantity:eq.quantity,unit:eq.unit||'项',unitPrice:eq.unitPrice,description:eq.brand?'品牌: '+eq.brand:'',category:'设备产品'})});
if(room.hasCustom)room.customItems.forEach(function(cp){var qty,unit,desc='';var type=cp.type||'';if(type==='特殊五金'||type==='特殊工艺'){qty=cp.quantity||1;unit=cp.unit||'项';desc=''}else if(type==='橱柜上柜'||type==='橱柜下柜'||type==='电视柜'||type==='踢脚线'){qty=cp.length||0;unit='m';desc='长度: '+cp.length+'m'}else{qty=Math.round((cp.length||0)*(cp.height||0)*100)/100;unit='㎡';desc='尺寸: '+(cp.length||0)+'×'+(cp.height||0)+'m'}var cat=type==='特殊五金'?'特殊五金':type==='特殊工艺'?'特殊工艺':'定制产品';items.push({id:uid(),roomId:room.id,name:cp.name,quantity:qty,unit:unit,unitPrice:cp.unitPrice,description:desc,category:cat})});
if(room.hasFeatureWall)room.featureWallItems.forEach(function(fw){items.push({id:uid(),roomId:room.id,name:fw.name,quantity:fw.area,unit:'㎡',unitPrice:fw.unitPrice,description:'',category:'背景墙'})});
return items}
function regenerateAllQuotes(){S.quoteItems=[];S.rooms.forEach(function(r){S.quoteItems=S.quoteItems.concat(generateRoomItems(r))});regenerateUtilityItems();syncPricesFromMaterials();var qm=S.customerInfo.quoteMode||'full';if(qm==='full'){regenerateMainMaterialItems()}else{S.productQuoteItems=S.productQuoteItems.filter(function(q){return q.mainCategory!=='main_material'&&q.mainCategory!=='auxiliary'})}renderQuoteTable();renderSummary()}
function regenerateMainMaterialItems(){S.productQuoteItems=S.productQuoteItems.filter(function(q){return q.mainCategory!=='main_material'&&q.mainCategory!=='auxiliary'});var mmProducts=S.products.filter(function(p){return p.mainCategory==='main_material'});if(!mmProducts.length)return;var fg={};S.rooms.forEach(function(r){var f=r.floor||'一楼';if(!fg[f])fg[f]=[];fg[f].push(r)});Object.keys(fg).forEach(function(fl){fg[fl].forEach(function(room){mmProducts.forEach(function(prod){var qty=0;var st=room.spaceTypeId||'';if(prod.subCategory==='pm_tiles'){if(st==='st_bathroom'||st==='st_kitchen')qty=room.area}else if(prod.subCategory==='pm_flooring'){if(st!=='st_bathroom'&&st!=='st_kitchen')qty=room.area}else if(prod.subCategory==='pm_sanitary'){if(st==='st_bathroom')qty=1}else if(prod.subCategory==='pm_doors'){qty=(room.doors||[]).length}else if(prod.subCategory==='pm_paint'){qty=room.area}else if(prod.subCategory==='pm_wallpaper'){qty=room.area}else if(prod.subCategory==='pm_lighting'){qty=1}else if(prod.subCategory==='pm_switches'){qty=1}else if(prod.subCategory==='pm_hardware'){qty=1}else if(prod.subCategory==='pm_skirting'){qty=1}if(qty>0&&prod.unitPrice>0){var ex=S.productQuoteItems.find(function(q){return q.productId===prod.id&&q.roomId===room.id});if(!ex){S.productQuoteItems.push({id:uid(),productId:prod.id,roomId:room.id,name:prod.name,brand:prod.brand,model:prod.model,mainCategory:'main_material',subCategory:prod.subCategory,specifications:prod.specifications,material:prod.material,color:prod.color,quantity:qty,unit:prod.unit,unitPrice:prod.unitPrice,description:prod.description||'',notes:prod.notes||'',photo:prod.photo||''})}}})})})}
function regenerateUtilityItems(){S.quoteItems=S.quoteItems.filter(function(q){return q.roomId!=='__utility__'});var area=parseFloat(S.customerInfo.area)||0;if(!area)return;S.materials.filter(function(m){return m.calcType==='building_area'}).forEach(function(mat){var qty=area;if(mat.name.includes('开关'))qty=Math.round(area/3);if(mat.prices[S.currentPlan]<=0)return;var desc=mat.description||'';if(mat.processDetail&&mat.processDetail[S.currentPlan])desc=mat.processDetail[S.currentPlan];S.quoteItems.push({id:uid(),materialId:mat.id,roomId:'__utility__',name:mat.name,quantity:Math.round(qty*100)/100,unit:mat.unit,unitPrice:mat.prices[S.currentPlan],description:desc,category:mat.category})})}
function syncPricesFromMaterials(){S.quoteItems.forEach(function(qi){if(qi.materialId){var m=S.materials.find(function(x){return x.id===qi.materialId});if(m){if(m.prices[S.currentPlan]>0)qi.unitPrice=m.prices[S.currentPlan];var desc=m.description||'';if(m.processDetail&&m.processDetail[S.currentPlan])desc=m.processDetail[S.currentPlan];else if(m.brand&&m.brand!=='-')desc+=' | '+m.brand;qi.description=desc;qi.name=m.name;qi.unit=m.unit;qi.category=m.category}}})}
function syncPricesFromProducts(){S.productQuoteItems.forEach(function(qi){if(qi.productId){var p=S.products.find(function(x){return x.id===qi.productId});if(p){qi.unitPrice=p.unitPrice;qi.name=p.name;qi.brand=p.brand;qi.model=p.model;qi.specifications=p.specifications;qi.material=p.material;qi.color=p.color;qi.description=p.description||'';qi.notes=p.notes||''}}})}

