function renderQuoteTable(){var w=document.getElementById('quoteTableWrapper');var qm=S.customerInfo.quoteMode||'full';var addBtn=document.getElementById('addProductBtn');if(addBtn)addBtn.style.display=qm==='full'?'':'none';if(!S.rooms.length&&!S.quoteItems.length&&!S.productQuoteItems.length){w.innerHTML='<div class="empty-state"><div class="icon">📋</div><p>添加房间后自动生成</p></div>';return}
var h='<table class="quote-table"><thead><tr><th class="col-num resizable" data-col="num">序号</th><th class="col-name resizable" data-col="name">项目</th><th class="col-qty resizable" data-col="qty">数量</th><th class="col-unit resizable" data-col="unit">单位</th><th class="col-price resizable" data-col="price">单价</th><th class="col-amount resizable" data-col="amount">金额</th><th class="col-desc resizable" data-col="desc">说明</th><th class="col-action no-print">操作</th></tr></thead><tbody>';
var catOrd=['防水工程','泥瓦工程','木作工程','油漆工程','墙面工程','地面工程','顶面工程','门窗工程','暖气改造','下水改造','安装工程','楼梯工程','设备产品','定制产品','特殊五金','特殊工艺','背景墙','自定义'];
var fg={};S.rooms.forEach(function(r){var f=r.floor||'一楼';if(!fg[f])fg[f]=[];fg[f].push(r)});
var floors=Object.keys(fg).sort(function(a,b){return floorSortKey(a)-floorSortKey(b)});
var allSections=[];
floors.forEach(function(fl){var rooms=fg[fl];var fi=S.quoteItems.filter(function(q){return rooms.some(function(r){return r.id===q.roomId})&&q.category!=='拆除工程'&&q.category!=='砌筑工程'});if(fi.length)allSections.push({type:'floor',id:'floor-'+fl,label:'🏗️ '+fl,items:fi,rooms:rooms})});
var demItems=S.quoteItems.filter(function(q){return q.category==='拆除工程'});if(demItems.length)allSections.push({type:'section',id:'demolition',label:'🔨 拆除工程',items:demItems});
var masItems=S.quoteItems.filter(function(q){return q.category==='砌筑工程'});if(masItems.length)allSections.push({type:'section',id:'masonry',label:'🧱 砌筑工程',items:masItems});
var ui=S.quoteItems.filter(function(q){return q.roomId==='__utility__'});if(ui.length)allSections.push({type:'section',id:'utility',label:'⚡ 水电暖气下水',items:ui});
allSections.forEach(function(sec){var sT=sec.items.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
h+='<tr class="floor-row" onclick="toggleRoomCollapse(\''+sec.id+'\')" style="cursor:pointer"><td colspan="5" style="text-align:left;font-weight:600;color:var(--text)"><span class="room-collapse-icon" id="icon-'+sec.id+'">▼</span> '+sec.label+'</td><td></td><td style="text-align:right;font-weight:600;color:var(--accent)">¥'+fmt(sT)+'</td><td class="no-print"></td></tr>';
if(sec.type==='floor'){sec.rooms.forEach(function(room){var ri=sec.items.filter(function(q){return q.roomId===room.id});if(!ri.length)return;var rT=ri.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);var seq=1;
h+='<tr class="sub-row room-toggle room-item-row" data-room-id="'+sec.id+'" onclick="toggleRoomCollapse(\''+room.id+'\')"><td colspan="5" style="padding-left:14px;cursor:pointer;text-align:left"><span class="room-collapse-icon" id="icon-'+room.id+'">▼</span> 📍 '+esc(room.name)+'</td><td></td><td style="text-align:right;font-weight:600;color:var(--accent)">¥'+fmt(rT)+'</td><td class="no-print"></td></tr>';
catOrd.forEach(function(cat){var ci=ri.filter(function(q){return q.category===cat});if(!ci.length)return;var cT=ci.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);h+='<tr class="room-item-row" data-room-id="'+sec.id+'" data-room-id2="'+room.id+'"><td colspan="5" style="text-align:left;padding-left:20px;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">▸ '+cat+'</td><td style="text-align:right;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">¥'+fmt(cT)+'</td><td></td><td class="no-print"></td></tr>';ci.forEach(function(qi){h+=qRow(qi,seq++,sec.id,room.id)})});h+='<tr class="room-item-row no-print" data-room-id="'+sec.id+'" data-room-id2="'+room.id+'"><td colspan="8" style="text-align:left;padding-left:24px;padding-top:2px;padding-bottom:2px"><button class="btn btn-outline btn-sm" style="font-size:10px;padding:1px 8px;border-radius:4px" onclick="showRoomItemPicker(\''+room.id+'\')">+ 添加项目</button><div id="picker-'+room.id+'" style="display:none;margin-top:4px"></div></td></tr>'})}else{var seq=1;sec.items.forEach(function(q){h+=qRow(q,seq++,sec.id)})}});
var ci2=S.quoteItems.filter(function(q){return q.roomId==='__custom__'});
if(ci2.length){var cs=1;
h+='<tr class="cat-row"><td colspan="5" style="text-align:left;font-weight:600;color:var(--text)">📝 自定义</td><td></td><td></td><td class="no-print"></td></tr>';
ci2.forEach(function(q){h+=qRow(q,cs++)})}
if(S.productQuoteItems.length){
var qm=S.customerInfo.quoteMode||'full';
var showCats=qm==='full'?PRODUCT_MAIN_CATEGORIES:PRODUCT_MAIN_CATEGORIES.filter(function(mc){return mc.id!=='equipment'&&mc.id!=='soft_furnishing'});
showCats.forEach(function(mc){var pi=S.productQuoteItems.filter(function(q){return q.mainCategory===mc.id});if(!pi.length)return;var pT=pi.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);var ps=1;
h+='<tr class="cat-row"><td colspan="5" style="text-align:left;font-weight:600;color:var(--text)">'+mc.icon+' '+mc.name+'</td><td></td><td style="text-align:right;font-weight:600;color:var(--accent)">¥'+fmt(pT)+'</td><td class="no-print"></td></tr>';
var subG={};pi.forEach(function(q){if(!subG[q.subCategory])subG[q.subCategory]=[];subG[q.subCategory].push(q)});
Object.keys(subG).forEach(function(subId){var subI=subG[subId];var sT=subI.reduce(function(s,q){return s+q.quantity*q.unitPrice},0);
h+='<tr><td colspan="5" style="text-align:left;padding-left:20px;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">▸ '+getSubCatLabel(mc.id,subId)+'</td><td style="text-align:right;font-size:10px;color:var(--text-dim);border-bottom:1px solid var(--border)">¥'+fmt(sT)+'</td><td></td><td class="no-print"></td></tr>';
subI.forEach(function(q){h+=qRow(q,ps++)})})})}h+='<tr><td colspan="7" style="text-align:right;padding-right:12px"><button class="btn btn-outline btn-sm no-print" onclick="addCustomQuoteItem()">+ 自定义</button></td><td class="no-print"></td></tr>';h+='</tbody></table>';w.innerHTML=h}
function qRow(qi,seq,sectionId,roomId){var a=qi.quantity*qi.unitPrice;var cls='room-item-row';var attrs=' data-room-id="'+sectionId+'"';if(roomId)attrs+=' data-room-id2="'+roomId+'"';return '<tr class="'+cls+'"'+attrs+'><td>'+seq+'</td><td><input class="qt-input qt-name" value="'+esc(qi.name)+'" onchange="updateQI(\''+qi.id+'\',\'name\',this.value)"></td><td><input class="qt-input qt-qty" type="number" value="'+qi.quantity+'" step="0.01" onchange="updateQI(\''+qi.id+'\',\'quantity\',this.value)"></td><td><input class="qt-input qt-unit" value="'+esc(qi.unit)+'" onchange="updateQI(\''+qi.id+'\',\'unit\',this.value)"></td><td><input class="qt-input qt-price" type="number" value="'+qi.unitPrice+'" step="0.01" onchange="updateQI(\''+qi.id+'\',\'unitPrice\',this.value)"></td><td class="col-amount">¥'+fmt(a)+'</td><td><input class="qt-input qt-desc" value="'+esc(qi.description||'')+'" onchange="updateQI(\''+qi.id+'\',\'description\',this.value)"></td><td class="no-print"><button class="btn-x" onclick="deleteQI(\''+qi.id+'\')">×</button></td></tr>'}
function updateQI(id,f,v){pushUndoState();var q=S.quoteItems.concat(S.productQuoteItems).find(function(x){return x.id===id});if(!q)return;if(f==='quantity'||f==='unitPrice')q[f]=parseFloat(v)||0;else q[f]=v;renderQuoteTable();renderSummary();markDirty()}
function deleteQI(id){pushUndoState();S.quoteItems=S.quoteItems.filter(function(q){return q.id!==id});S.productQuoteItems=S.productQuoteItems.filter(function(q){return q.id!==id});renderQuoteTable();renderSummary();markDirty()}
function addCustomQuoteItem(){pushUndoState();S.quoteItems.push({id:uid(),roomId:'__custom__',name:'自定义项目',quantity:1,unit:'项',unitPrice:0,description:'',category:'自定义'});renderQuoteTable();renderSummary();markDirty()}

function showRoomItemPicker(roomId){
  var el=document.getElementById('picker-'+roomId);
  if(!el)return;
  if(el.style.display!=='none'){el.style.display='none';return}
  document.querySelectorAll('[id^="picker-"]').forEach(function(p){if(p.id!=='picker-'+roomId)p.style.display='none'});
  el.style.display='block';
  el.innerHTML='<div style="position:relative"><input id="pickerSearch-'+roomId+'" placeholder="输入关键词搜索材料/产品..." oninput="searchRoomItems(\''+roomId+'\')" style="width:100%;padding:6px 8px;font-size:12px;border:1px solid var(--border);border-radius:4px;box-sizing:border-box;outline:none" autofocus><div id="pickerResults-'+roomId+'" style="max-height:220px;overflow-y:auto;margin-top:4px;border:1px solid var(--border);border-radius:4px;background:var(--card)"></div></div>';
  searchRoomItems(roomId);
  setTimeout(function(){var inp=document.getElementById('pickerSearch-'+roomId);if(inp)inp.focus()},50);
}
function searchRoomItems(roomId){
  var sr=((document.getElementById('pickerSearch-'+roomId)||{}).value||'').toLowerCase();
  var el=document.getElementById('pickerResults-'+roomId);
  if(!el)return;
  var results=[];
  S.materials.forEach(function(m){
    if(sr&&m.name.toLowerCase().indexOf(sr)<0&&(m.brand||'').toLowerCase().indexOf(sr)<0&&(m.category||'').toLowerCase().indexOf(sr)<0)return;
    var price=m.prices[S.currentPlan]||0;
    results.push({type:'material',id:m.id,name:m.name,brand:m.brand||'',unit:m.unit,price:price,desc:m.description||'',category:m.category,tag:'施工'})
  });
  S.products.forEach(function(p){
    if(sr&&p.name.toLowerCase().indexOf(sr)<0&&(p.brand||'').toLowerCase().indexOf(sr)<0&&(p.model||'').toLowerCase().indexOf(sr)<0)return;
    results.push({type:'product',id:p.id,name:p.name,brand:p.brand||'',unit:p.unit,price:p.unitPrice,desc:p.description||'',category:'自定义',tag:'产品'})
  });
  if(!results.length){el.innerHTML='<div style="padding:12px;text-align:center;color:var(--text-dim);font-size:11px">无匹配结果</div>';return}
  results=results.slice(0,50);
  el.innerHTML=results.map(function(r){
    return '<div style="padding:6px 8px;cursor:pointer;border-bottom:1px solid var(--border);font-size:11px;display:flex;justify-content:space-between;align-items:center" onclick="pickRoomItem(\''+roomId+'\',\''+r.type+'\',\''+r.id+'\')" onmouseover="this.style.background=\'var(--accent-dim)\'" onmouseout="this.style.background=\'transparent\'"><div style="flex:1;min-width:0"><div style="font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+esc(r.name)+' <span style="color:var(--text-dim);font-size:10px">'+esc(r.brand)+'</span></div><div style="color:var(--text-dim);font-size:9px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+esc(r.desc).substring(0,80)+'</div></div><div style="text-align:right;white-space:nowrap;margin-left:8px"><div><span style="color:var(--accent);font-weight:600">¥'+fmt(r.price)+'</span><span style="color:var(--text-dim)">/'+esc(r.unit)+'</span></div><span style="font-size:9px;padding:1px 4px;border-radius:3px;background:var(--accent-dim);color:var(--text-dim)">'+esc(r.tag)+'</span></div></div>'
  }).join('');
}
function pickRoomItem(roomId,type,itemId){
  pushUndoState();
  var room=S.rooms.find(function(r){return r.id===roomId});
  if(type==='material'){
    var m=S.materials.find(function(x){return x.id===itemId});
    if(!m)return;
    var price=m.prices[S.currentPlan]||0;
    var qty=1;
    if(room&&m.calcType){
      if(m.calcType==='wall_area'&&room.wallArea)qty=room.wallArea;
      else if(m.calcType==='floor_area'&&room.floorArea)qty=room.floorArea;
      else if(m.calcType==='ceiling_area'&&room.ceilingArea)qty=room.ceilingArea;
      else if(m.calcType==='skirting'&&room.perimeter)qty=room.perimeter;
      else if(m.calcType==='door_count'&&room.doors)qty=room.doors.length;
      else if(m.calcType==='length_m'&&room.perimeter)qty=room.perimeter;
      else if(m.calcType==='building_area'&&room.area)qty=room.area;
    }
    S.quoteItems.push({id:uid(),roomId:roomId,materialId:m.id,name:m.name,quantity:Math.round(qty*100)/100,unit:m.unit,unitPrice:price,description:m.description||'',category:m.category});
  }else{
    var p=S.products.find(function(x){return x.id===itemId});
    if(!p)return;
    S.quoteItems.push({id:uid(),roomId:roomId,name:p.name,quantity:1,unit:p.unit,unitPrice:p.unitPrice,description:p.description||'',category:'自定义'});
  }
  var el=document.getElementById('picker-'+roomId);
  if(el)el.style.display='none';
  renderQuoteTable();renderSummary();markDirty();
}

// ==================== SUMMARY ====================
function renderSummary(){var el=document.getElementById('summarySection');var qm=S.customerInfo.quoteMode||'full';var eT=S.quoteItems.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var visiblePQI=qm==='full'?S.productQuoteItems:S.productQuoteItems.filter(function(q){return q.mainCategory!=='equipment'&&q.mainCategory!=='soft_furnishing'});var pT=visiblePQI.reduce(function(s,i){return s+(i.quantity||0)*(i.unitPrice||0)},0);var sub=eT+pT;var mg=sub*S.managementFeeRate/100;var tx=sub*S.taxRate/100;var g=sub+mg+tx+S.garbageFee+S.protectionFee;if(qm==='full'){var eMg=eT*S.managementFeeRate/100;var eTx=eT*S.taxRate/100;var eTotal=eT+eMg+eTx+S.garbageFee+S.protectionFee;var pMg=pT*S.managementFeeRate/100;var pTx=pT*S.taxRate/100;var pTotal=pT+pMg+pTx;var prodBreak='';if(pT>0){var showCats=PRODUCT_MAIN_CATEGORIES;showCats.forEach(function(mc){var t=visiblePQI.filter(function(q){return q.mainCategory===mc.id}).reduce(function(s,q){return s+q.quantity*q.unitPrice},0);if(t>0)prodBreak+='<div class="summary-row"><span class="summary-label" style="padding-left:20px">  '+mc.icon+' '+mc.name+'</span><span class="summary-value">¥'+fmt(t)+'</span></div>'})}el.innerHTML='<div style="margin-bottom:10px;padding:10px 14px;background:rgba(59,130,246,0.08);border-radius:8px;border:1px solid rgba(59,130,246,0.15)"><div style="font-size:12px;font-weight:700;color:var(--accent);margin-bottom:8px">🔨 施工报价</div><div class="summary-row"><span class="summary-label">施工费用</span><span class="summary-value">¥'+fmt(eT)+'</span></div><div class="summary-row"><span class="summary-label">管理费 (<input class="rate-input" value="'+S.managementFeeRate+'" onchange="S.managementFeeRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(eMg)+'</span></div><div class="summary-row"><span class="summary-label">税金 (<input class="rate-input" value="'+S.taxRate+'" onchange="S.taxRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(eTx)+'</span></div><div class="summary-row"><span class="summary-label">垃圾清运 <input class="rate-input" value="'+S.garbageFee+'" onchange="S.garbageFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.garbageFee)+'</span></div><div class="summary-row"><span class="summary-label">成品保护 <input class="rate-input" value="'+S.protectionFee+'" onchange="S.protectionFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.protectionFee)+'</span></div><div class="summary-row" style="background:var(--accent-dim);padding:8px 14px;border-radius:6px;margin-top:4px"><span class="summary-label" style="font-weight:600">施工报价小计</span><span class="summary-value" style="color:var(--accent);font-weight:700">¥'+fmt(eTotal)+'</span></div></div>'+(pT>0?'<div style="margin-bottom:10px;padding:10px 14px;background:rgba(16,185,129,0.08);border-radius:8px;border:1px solid rgba(16,185,129,0.15)"><div style="font-size:12px;font-weight:700;color:var(--success);margin-bottom:8px">🧱 主材报价</div><div class="summary-row"><span class="summary-label">主材费用</span><span class="summary-value">¥'+fmt(pT)+'</span></div>'+prodBreak+'<div class="summary-row"><span class="summary-label">管理费 ('+S.managementFeeRate+'%)</span><span class="summary-value">¥'+fmt(pMg)+'</span></div><div class="summary-row"><span class="summary-label">税金 ('+S.taxRate+'%)</span><span class="summary-value">¥'+fmt(pTx)+'</span></div><div class="summary-row" style="background:rgba(16,185,129,0.12);padding:8px 14px;border-radius:6px;margin-top:4px"><span class="summary-label" style="font-weight:600">主材报价小计</span><span class="summary-value" style="color:var(--success);font-weight:700">¥'+fmt(pTotal)+'</span></div></div>':'')+'<div class="summary-row total" style="background:var(--accent-dim);padding:12px 14px;border-radius:8px"><span class="summary-label" style="font-weight:700;font-size:14px">报价总计</span><span class="summary-value" style="font-weight:700;font-size:16px;color:var(--accent)">¥'+fmt(eTotal+pTotal)+'</span></div>'}else{var mg2=sub*S.managementFeeRate/100;var tx2=sub*S.taxRate/100;var g2=sub+mg2+tx2+S.garbageFee+S.protectionFee;el.innerHTML='<div class="summary-row"><span class="summary-label">工程报价</span><span class="summary-value">¥'+fmt(eT)+'</span></div>'+(pT>0?'<div class="summary-row"><span class="summary-label">产品清单</span><span class="summary-value">¥'+fmt(pT)+'</span></div>':'')+'<div class="summary-row" style="background:var(--accent-dim);padding:10px 14px;border-radius:8px;margin-top:6px"><span class="summary-label" style="font-weight:600">直接费用合计</span><span class="summary-value" style="color:var(--accent)">¥'+fmt(sub)+'</span></div><div class="summary-row"><span class="summary-label">管理费 (<input class="rate-input" value="'+S.managementFeeRate+'" onchange="S.managementFeeRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(mg2)+'</span></div><div class="summary-row"><span class="summary-label">税金 (<input class="rate-input" value="'+S.taxRate+'" onchange="S.taxRate=parseFloat(this.value)||0;renderSummary()">%)</span><span class="summary-value">¥'+fmt(tx2)+'</span></div><div class="summary-row"><span class="summary-label">垃圾清运 <input class="rate-input" value="'+S.garbageFee+'" onchange="S.garbageFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.garbageFee)+'</span></div><div class="summary-row"><span class="summary-label">成品保护 <input class="rate-input" value="'+S.protectionFee+'" onchange="S.protectionFee=parseFloat(this.value)||0;renderSummary()"></span><span class="summary-value">¥'+fmt(S.protectionFee)+'</span></div><div class="summary-row total"><span class="summary-label">报价总计</span><span class="summary-value">¥'+fmt(g2)+'</span></div>'}}

// ==================== MATERIAL/SPACE LIBRARY ====================
function openMaterialLib(){renderMaterialLib();openModal('materialLibModal')}
function renderMaterialLib(){document.getElementById('materialLibBody').innerHTML='<div class="lib-filter"><select id="matCatFilter" onchange="renderMaterialTable()"><option value="">全部</option>'+CATEGORIES.map(function(c){return'<option value="'+c+'">'+c+'</option>'}).join('')+'</select><input id="matSearch" placeholder="搜索..." oninput="renderMaterialTable()"><button class="btn btn-primary btn-sm" onclick="showMaterialForm()">+ 添加</button><button class="btn btn-outline btn-sm" onclick="batchUpdateBrand()">批量改品牌</button></div><div id="matFormArea"></div><div id="matTableArea"></div>';renderMaterialTable()}
function getUniqueBrands(){var b=[];S.materials.forEach(function(m){if(m.brand&&m.brand!=='-'&&b.indexOf(m.brand)===-1)b.push(m.brand)});return b.sort()}
function renderMaterialTable(){var cv=(document.getElementById('matCatFilter')||{}).value;var sr=((document.getElementById('matSearch')||{}).value||'').toLowerCase();var m=S.materials;if(cv)m=m.filter(function(x){return x.category===cv});if(sr)m=m.filter(function(x){return x.name.toLowerCase().includes(sr)||(x.brand||'').toLowerCase().includes(sr)});var el=document.getElementById('matTableArea');if(!m.length){el.innerHTML='<div class="empty-state"><p>暂无</p></div>';return}el.innerHTML='<table class="lib-table"><thead><tr><th>名称</th><th>品牌</th><th>单位</th><th>奢享</th><th>优享</th><th>标准</th><th>分类</th><th>说明</th><th>操作</th></tr></thead><tbody>'+m.map(function(x){return'<tr><td>'+esc(x.name)+'</td><td>'+esc(x.brand)+'</td><td>'+esc(x.unit)+'</td><td>'+(x.prices.luxury||'-')+'</td><td>'+(x.prices.premium||'-')+'</td><td>'+(x.prices.standard||'-')+'</td><td>'+esc(x.category)+'</td><td style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+esc(x.description)+'</td><td><button class="btn btn-outline btn-sm" onclick="editMaterial(\''+x.id+'\')">编辑</button> <button class="btn btn-danger btn-sm" onclick="deleteMaterial(\''+x.id+'\')">删除</button></td></tr>'}).join('')+'</tbody></table>'}
function batchUpdateBrand(){var b=getUniqueBrands();document.getElementById('matFormArea').innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>原品牌</label><select id="batchOldBrand">'+b.map(function(x){return'<option>'+esc(x)+'</option>'}).join('')+'</select></div><div class="form-group"><label>新品牌</label><input id="batchNewBrand"></div></div><div style="margin-top:6px"><button class="btn btn-primary btn-sm" onclick="doBatchUpdateBrand()">确认</button></div></div>'}
function doBatchUpdateBrand(){var o=document.getElementById('batchOldBrand').value;var n=document.getElementById('batchNewBrand').value.trim();if(!o||!n)return;var c=0;S.materials.forEach(function(m){if(m.brand===o){m.brand=n;c++}});if(c>0){document.getElementById('matFormArea').innerHTML='';renderMaterialTable();syncPricesFromMaterials();renderQuoteTable();renderSummary();saveSettings();showToast('已更新'+c+'个')}else showToast('未找到')}
function showMaterialForm(mat){S.editingMaterialId=mat?mat.id:null;var area=document.getElementById('matFormArea');var stC=S.spaceTypes.map(function(s){return'<label style="font-size:10px;display:inline-flex;align-items:center;gap:2px;margin-right:4px"><input type="checkbox" class="mat-st-filter" value="'+s.id+'" '+(mat&&mat.spaceTypeFilter&&mat.spaceTypeFilter.includes(s.id)?'checked':'')+'>'+s.name+'</label>'}).join('');var pd=mat&&mat.processDetail?mat.processDetail:{luxury:'',premium:'',standard:''};area.innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>名称</label><input id="mfName" value="'+(mat?esc(mat.name):'')+'"></div><div class="form-group"><label>品牌</label><input id="mfBrand" value="'+(mat?esc(mat.brand):'')+'"></div><div class="form-group"><label>单位</label><input id="mfUnit" value="'+(mat?esc(mat.unit):'㎡')+'"></div><div class="form-group"><label>分类</label><select id="mfCategory">'+CATEGORIES.map(function(c){return'<option value="'+c+'" '+(mat&&mat.category===c?'selected':'')+'>'+c+'</option>'}).join('')+'</select></div><div class="form-group"><label>计算</label><select id="mfCalcType">'+Object.keys(CALC_TYPES).map(function(k){return'<option value="'+k+'" '+(mat&&mat.calcType===k?'selected':'')+'>'+CALC_TYPES[k]+'</option>'}).join('')+'</select></div><div class="form-group"><label>奢享</label><input type="number" id="mfPL" value="'+(mat?mat.prices.luxury:0)+'"></div><div class="form-group"><label>优享</label><input type="number" id="mfPP" value="'+(mat?mat.prices.premium:0)+'"></div><div class="form-group"><label>标准</label><input type="number" id="mfPS" value="'+(mat?mat.prices.standard:0)+'"></div><div class="form-group full"><label>说明</label><div style="display:flex;gap:6px;align-items:center"><input id="mfDesc" value="'+(mat?esc(mat.description):'')+'" style="flex:1"><button class="btn btn-info btn-sm" onclick="aiOptimizeField(\'mfDesc\',\'construction\')" title="AI智能优化说明">🤖</button></div></div><div class="form-group full"><label>奢享工艺</label><div style="display:flex;gap:6px;align-items:center"><input id="mfPDL" value="'+esc(pd.luxury)+'" style="flex:1"><button class="btn btn-info btn-sm" onclick="aiOptimizeField(\'mfPDL\',\'construction\')" title="AI智能优化工艺">🤖</button></div></div><div class="form-group full"><label>优享工艺</label><div style="display:flex;gap:6px;align-items:center"><input id="mfPDP" value="'+esc(pd.premium)+'" style="flex:1"><button class="btn btn-info btn-sm" onclick="aiOptimizeField(\'mfPDP\',\'construction\')" title="AI智能优化工艺">🤖</button></div></div><div class="form-group full"><label>标准工艺</label><div style="display:flex;gap:6px;align-items:center"><input id="mfPDS" value="'+esc(pd.standard)+'" style="flex:1"><button class="btn btn-info btn-sm" onclick="aiOptimizeField(\'mfPDS\',\'construction\')" title="AI智能优化工艺">🤖</button></div></div><div class="form-group full"><label>适用空间</label><div>'+stC+'</div></div></div><div style="margin-top:6px;display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="saveMaterial()">保存</button><button class="btn btn-outline btn-sm" onclick="document.getElementById(\'matFormArea\').innerHTML=\'\'">取消</button></div></div>'}
function editMaterial(mid){var m=S.materials.find(function(x){return x.id===mid});if(m)showMaterialForm(m)}
function saveMaterial(){var n=document.getElementById('mfName').value.trim();if(!n){showToast('请输入名称');return}var stF=[];document.querySelectorAll('.mat-st-filter:checked').forEach(function(c){stF.push(c.value)});var d={id:S.editingMaterialId||uid(),name:n,brand:document.getElementById('mfBrand').value.trim(),unit:document.getElementById('mfUnit').value.trim(),prices:{luxury:parseFloat(document.getElementById('mfPL').value)||0,premium:parseFloat(document.getElementById('mfPP').value)||0,standard:parseFloat(document.getElementById('mfPS').value)||0},description:document.getElementById('mfDesc').value.trim(),category:document.getElementById('mfCategory').value,calcType:document.getElementById('mfCalcType').value,spaceTypeFilter:stF,processDetail:{luxury:document.getElementById('mfPDL').value.trim(),premium:document.getElementById('mfPDP').value.trim(),standard:document.getElementById('mfPDS').value.trim()}};if(S.editingMaterialId){var i=S.materials.findIndex(function(x){return x.id===S.editingMaterialId});if(i>=0)S.materials[i]=d}else S.materials.push(d);S.editingMaterialId=null;document.getElementById('matFormArea').innerHTML='';renderMaterialTable();syncPricesFromMaterials();renderQuoteTable();renderSummary();saveSettings();showToast('已保存')}
function deleteMaterial(mid){if(!confirm('确定删除？'))return;S.materials=S.materials.filter(function(m){return m.id!==mid});S.quoteItems=S.quoteItems.filter(function(q){return q.materialId!==mid});renderMaterialTable();renderQuoteTable();renderSummary();saveSettings();markDirty()}
function openSpaceTypeLib(){renderSpaceTypeLib();openModal('spaceTypeLibModal')}
function renderSpaceTypeLib(){document.getElementById('spaceTypeLibBody').innerHTML='<div style="margin-bottom:10px"><button class="btn btn-primary btn-sm" onclick="showSpaceTypeForm()">+ 添加</button></div><div id="stListArea"></div>';renderSpaceTypeList()}
function renderSpaceTypeList(){var el=document.getElementById('stListArea');if(!S.spaceTypes.length){el.innerHTML='<div class="empty-state"><p>暂无</p></div>';return}el.innerHTML=S.spaceTypes.map(function(st){return '<div class="st-item"><div class="st-item-header"><span class="st-item-name">'+st.icon+' '+esc(st.name)+'</span><div><button class="btn btn-outline btn-sm" onclick="editSpaceType(\''+st.id+'\')">编辑</button> <button class="btn btn-danger btn-sm" onclick="deleteSpaceType(\''+st.id+'\')">删除</button></div></div></div>'}).join('')}
function showSpaceTypeForm(st){S.editingSpaceTypeId=st?st.id:null;var area=document.getElementById('stListArea');var emojis=['🛋️','🍽️','🛏️','🍳','🚿','🌿','🚪','📐','📚','📦','🏠','🏢','🛁','🎮','👶','👗','🧹','🏋️'];area.innerHTML='<div class="mat-form"><div class="form-grid"><div class="form-group"><label>名称</label><input id="stName" value="'+(st?esc(st.name):'')+'"></div><div class="form-group"><label>图标</label><select id="stIcon">'+emojis.map(function(e){return'<option value="'+e+'" '+(st&&st.icon===e?'selected':'')+'>'+e+'</option>'}).join('')+'</select></div></div><div style="margin-top:6px;display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="saveSpaceType()">保存</button><button class="btn btn-outline btn-sm" onclick="renderSpaceTypeList()">取消</button></div></div>'}
function editSpaceType(id){var st=S.spaceTypes.find(function(s){return s.id===id});if(st)showSpaceTypeForm(st)}
function saveSpaceType(){var n=document.getElementById('stName').value.trim();if(!n)return;var d={id:S.editingSpaceTypeId||uid(),name:n,icon:document.getElementById('stIcon').value};if(S.editingSpaceTypeId){var i=S.spaceTypes.findIndex(function(s){return s.id===S.editingSpaceTypeId});if(i>=0)S.spaceTypes[i]=d}else S.spaceTypes.push(d);S.editingSpaceTypeId=null;renderSpaceTypeList();saveSettings()}
function deleteSpaceType(id){if(!confirm('确定删除？'))return;S.spaceTypes=S.spaceTypes.filter(function(s){return s.id!==id});renderSpaceTypeList();saveSettings()}

